window.findeKatalogEintraege = function (code) {
  var norm = function (s) { return String(s).toLowerCase().replace(/[\s\-]/g, ''); };
  var n = norm(code);
  return window.KATALOG_DATA.filter(function (eintrag) {
    return (eintrag.codes || []).some(function (c) { return norm(c) === n; });
  });
};
